export const products: Product[] = Object.entries(categoryProducts).flatMap(([categoryId, names]) => {
  const categoryName = categories.find((category) => category.id === categoryId)?.name ?? 'προϊόντα';

  return names.map((name, index) => ({
    id: `${categoryId}-${slugify(name)}`,
    name,
    description: descriptions[name] ?? `${name} από τη συλλογή ${categoryName}, φτιαγμένο καθημερινά με φρέσκα υλικά και τη φροντίδα του Angelus Pastry & Bakery.`,
    characteristics: characteristics[name] ?? [],
    category_id: categoryId,
    image_url: productImages[name] ?? fallbackImages[categoryId],
    display_order: index + 1,
    featured: featuredNames.has(name),
    top: topNames.has(name),
  }));
});

